function pp(n){var m=n.match(/(\d+\.?\d*)\s*(lb|kg|g|gal|L|ml|oz|fl\.?oz|each|bunch|avocado|bun|roll|loaf|tin|ct|can|head)\s*$/i);if(m)return{s:parseFloat(m[1]),u:m[2]};m=n.match(/(\d+\.?\d*)(lb|kg|g|gal|L|ml|oz|each)\b/i);if(m)return{s:parseFloat(m[1]),u:m[2]};return null;}
function pq(s){if(!s)return{v:0,u:""};var c=s.replace(/,/g,"");var m=c.match(/^([\d.]+)\s*(.*)$/);return m?{v:parseFloat(m[1])||0,u:m[2].trim()}:{v:0,u:s};}
function gs(mx,miss){if(mx===0&&miss>=3)return{tier:"critical",label:"CRITICAL",color:"#991b1b",bg:"#fef2f2"};if(mx===0)return{tier:"red",label:"Cannot Produce",color:"#dc2626",bg:"#fef2f2"};if(mx<=4)return{tier:"yellow",label:"Running Low",color:"#b45309",bg:"#fffbeb"};return{tier:"green",label:"Full Capacity",color:"#047857",bg:"#ecfdf5"};}

var NAV=[{id:"capacity",label:"Capacity",icon:"\u25A3"},{id:"alerts",label:"Daily Alerts",icon:"\uD83D\uDD14"},{id:"overrides",label:"Overrides",icon:"\u2699\uFE0F"},{id:"calendar",label:"Weekly Plan",icon:"\uD83D\uDCC5"},{id:"inventory",label:"Inventory",icon:"\uD83D\uDCE6"},{id:"recipes",label:"All Recipes",icon:"\uD83C\uDF73"}];

export default function App(){
  var [inv,setInv]=useState(function(){var o={};Object.entries(RAW.ingredients).forEach(function(e){o[e[0]]=e[1].stock||0;});return o;});
  var [overrides,setOverrides]=useState([]);
  var [sel,setSel]=useState(null);
  var [view,setView]=useState("capacity");
  var [searchR,setSearchR]=useState("");
  var [searchI,setSearchI]=useState("");
  var [searchAll,setSearchAll]=useState("");
  var [filterTier,setFilterTier]=useState("all");
  var [ovIng,setOvIng]=useState("");var [ovQty,setOvQty]=useState("");var [ovReason,setOvReason]=useState("");var [ovFrom,setOvFrom]=useState("");var [ovTo,setOvTo]=useState("");

  // ═══ ALLOCATION ENGINE ═══
  var engine=useMemo(function(){
    // Step 1: Build demand map - for each ingredient, which recipes need it and how much
    var demandMap={};// {ingName: {recipeName: {base: baseUnitsPerBatch, est: estimatedDailyBatches}}}

    RAW.recipes.forEach(function(recipe){
      // Estimate daily batches from depletion data (use least-shared ingredient)
      var estimates=[];
      recipe.ingredients.forEach(function(ing){
        var dd=DOW_RAW[ing.name];if(!dd)return;
        var p=pq(ing.qty);if(p.v<=0)return;
        var pk=pp(ing.name);var ps=pk?pk.s:1;var pu=pk?pk.u:"unit";
        var depBase=tb(dd.a*ps,pu);var recBase=tb(p.v,p.u);
        if(depBase&&recBase&&depBase.c===recBase.c&&recBase.v>0){
          var rc=(RAW.ingredients[ing.name]||{}).recipe_count||1;
          estimates.push({est:depBase.v/recBase.v,rc:rc});
        }
      });
      estimates.sort(function(a,b){return a.rc===b.rc?b.est-a.est:a.rc-b.rc;});
      var dailyBatches=estimates.length>0?Math.max(0.5,Math.min(estimates[0].est,20)):1;

      recipe.ingredients.forEach(function(ing){
        var p=pq(ing.qty);if(p.v<=0)return;
        var recBase=tb(p.v,p.u);
        var basePerBatch=recBase?recBase.v:p.v;
        var cat=recBase?recBase.c:"x";
        if(!demandMap[ing.name])demandMap[ing.name]={};
        // If same recipe appears twice for same ingredient, sum the demand
        if(!demandMap[ing.name][recipe.name]){
          demandMap[ing.name][recipe.name]={base:basePerBatch,est:dailyBatches,cat:cat};
        } else {
          demandMap[ing.name][recipe.name].base+=basePerBatch;
        }
      });
    });

    // Step 2: Allocate each ingredient proportionally by demand weight
    var alloc={};// {ingName: {recipeName: {share, allocBase, allocBatches}}}
    Object.entries(demandMap).forEach(function(e){
      var ingName=e[0],recipes=e[1];
      var info=RAW.ingredients[ingName]||{};
      var sc=inv[ingName]||0;
      var pk=pp(ingName);var ps=pk?pk.s:1;var pu=pk?pk.u:"unit";
      var stockBase=tb(sc*ps,pu);
      var totalStock=stockBase?stockBase.v:sc*ps;

      var totalDemand=0;
      Object.values(recipes).forEach(function(r){totalDemand+=r.base*r.est;});

      alloc[ingName]={};
      Object.entries(recipes).forEach(function(re){
        var rName=re[0],rd=re[1];
        var share=totalDemand>0?(rd.base*rd.est)/totalDemand:1/Object.keys(recipes).length;
        var allocBase=totalStock*share;
        var allocBatches=rd.base>0?Math.floor(allocBase/rd.base):99999;
        alloc[ingName][rName]={share:Math.round(share*1000)/10,allocBase:Math.round(allocBase),allocBatches:allocBatches};
      });
    });

    // Step 3: Calculate per-recipe allocated capacity
    var recipes=[];
    RAW.recipes.forEach(function(recipe){
      var ings=[];var maxB=99999,bnI=null,missC=0;
      recipe.ingredients.forEach(function(ing){
        var p=pq(ing.qty);var sc=inv[ing.name]||0;var info=RAW.ingredients[ing.name]||{};
        var pk=pp(ing.name);var ps=pk?pk.s:1;var pu=pk?pk.u:"unit";
        if(sc<=0&&p.v>0)missC++;

        // Get allocated batches
        var a=alloc[ing.name]&&alloc[ing.name][recipe.name];
        var allocBatches=a?a.allocBatches:0;
        var sharePct=a?a.share:0;
        if(sc<=0&&p.v>0)allocBatches=0;

        if(allocBatches<maxB){maxB=allocBatches;bnI=ing.name;}

        ings.push({name:ing.name,perBatch:p.v,unit:p.u,sc:sc,ps:ps,pu:pu,ts:Math.round(sc*ps*100)/100,cm:allocBatches,sh:(info.recipe_count||1)>1,rc:info.recipe_count||1,cost:ing.cost||0,hd:!!info.has_data,ad:info.avg_daily||0,miss:sc<=0&&p.v>0,share:sharePct});
      });
      var fm=maxB>=99999?0:maxB;
      recipes.push({name:recipe.name,cat:recipe.category,mx:fm,bn:bnI,ings:ings,cpb:ings.reduce(function(s,i){return s+i.cost;},0),ic:ings.length,mc:missC,st:gs(fm,missC)});
    });
    return{recipes:recipes,alloc:alloc};
  },[inv]);

  var alerts=useMemo(function(){
    var list=[];
    engine.recipes.filter(function(r){return r.st.tier==="critical";}).forEach(function(r){list.push({type:"critical",title:r.name,desc:r.mc+" ingredients missing: "+r.ings.filter(function(i){return i.miss;}).map(function(i){return i.name.split(" ").slice(0,3).join(" ");}).join(", "),priority:1});});
    engine.recipes.filter(function(r){return r.st.tier==="red";}).forEach(function(r){list.push({type:"red",title:r.name,desc:"Missing: "+r.ings.filter(function(i){return i.miss;}).map(function(i){return i.name.split(" ").slice(0,3).join(" ");}).join(", "),priority:2});});
    Object.entries(RAW.ingredients).forEach(function(e){var n=e[0],info=e[1],sc=inv[n]||0;var pk=pp(n);var ps=pk?pk.s:1;var total=sc*ps;var avg=info.avg_daily||0;if(avg>0){var days=Math.round(total/avg);if(days<=2&&days>=0)list.push({type:"low_stock",title:n,desc:sc+" packs on hand ("+Math.round(total)+" total). Using "+avg.toFixed(1)+"/day.",days:days,priority:3});}});
    engine.recipes.filter(function(r){return r.st.tier==="yellow";}).forEach(function(r){list.push({type:"yellow",title:r.name,desc:"Only "+r.mx+" allocated batch"+(r.mx!==1?"es":"")+" possible. Bottleneck: "+(r.bn?r.bn.split(" ").slice(0,3).join(" "):"?"),priority:4});});
    list.sort(function(a,b){return a.priority-b.priority;});return list;
  },[engine,inv]);

  var calendar=useMemo(function(){
    var week={};DOW_ORDER.forEach(function(day,di){var short=DOW_SHORT[di];var dayR=[];
      engine.recipes.forEach(function(r){var estimates=[];r.ings.forEach(function(ing){var dd=DOW_RAW[ing.name];if(!dd||!dd.d||!dd.d[short])return;var dayUse=dd.d[short];if(ing.perBatch>0&&dayUse>0){var sb=tb(dayUse*ing.ps,ing.pu);var rb=tb(ing.perBatch,ing.unit);if(sb&&rb&&sb.c===rb.c&&rb.v>0)estimates.push(sb.v/rb.v);}});
        if(estimates.length>0){var est=Math.max(1,Math.round(Math.min.apply(null,estimates)));dayR.push({name:r.name,est:est,ok:est<=r.mx,mx:r.mx,st:r.st});}
      });dayR.sort(function(a,b){return b.est-a.est;});week[day]=dayR;
    });return week;
  },[engine]);

  var us=useCallback(function(n,v){setInv(function(p){var x=Object.assign({},p);x[n]=Math.max(0,v);return x;});},[]);
  var nav=function(v){setView(v);setSel(null);};
  var addOv=function(){if(!ovIng||!ovQty)return;var q=parseFloat(ovQty)||0;setOverrides(function(p){return[{id:Date.now(),ing:ovIng,qty:q,reason:ovReason,from:ovFrom,to:ovTo,time:new Date().toLocaleString(),user:"Chef"}].concat(p);});us(ovIng,(inv[ovIng]||0)-q);setOvIng("");setOvQty("");setOvReason("");setOvFrom("");setOvTo("");};

  var counts={green:0,yellow:0,red:0,critical:0};
  engine.recipes.forEach(function(r){counts[r.st.tier]++;});
  var alertBadge=alerts.filter(function(a){return a.priority<=2;}).length;

  var sorted=useMemo(function(){
    var a=engine.recipes.slice();
    if(filterTier!=="all")a=a.filter(function(r){return r.st.tier===filterTier;});
    if(searchR)a=a.filter(function(r){return r.name.toLowerCase().indexOf(searchR.toLowerCase())>=0;});
    a.sort(function(x,y){var o={critical:0,red:1,yellow:2,green:3};return(o[x.st.tier]||3)-(o[y.st.tier]||3);});
    return a;
  },[engine.recipes,filterTier,searchR]);

  return(
    <div style={{fontFamily:"system-ui,-apple-system,'Segoe UI',Roboto,sans-serif",display:"flex",minHeight:"100vh",background:"#f8f8f6",color:"#1a1a2e"}}>
      {/* SIDEBAR */}
      <div style={{position:"fixed",left:0,top:0,bottom:0,width:220,background:"#1a1a2e",display:"flex",flexDirection:"column",zIndex:100,overflowY:"auto"}}>
        <div style={{padding:"22px 18px 16px",borderBottom:"1px solid rgba(255,255,255,0.06)"}}><div style={{fontSize:18,fontWeight:700,color:"#c4a35a"}}>KEVA</div><div style={{fontSize:10,color:"rgba(255,255,255,0.3)",marginTop:3,letterSpacing:2}}>DELILAH LA</div></div>
        <nav style={{flex:1,padding:"12px 8px"}}>{NAV.map(function(item){var active=view===item.id&&!sel;return <button key={item.id} onClick={function(){nav(item.id);}} style={{display:"flex",alignItems:"center",gap:10,width:"100%",padding:"11px 14px",marginBottom:2,border:"none",borderRadius:8,background:active?"rgba(196,163,90,0.15)":"transparent",color:active?"#c4a35a":"rgba(255,255,255,0.4)",fontSize:13,fontWeight:active?600:400,cursor:"pointer",textAlign:"left",fontFamily:"inherit"}}><span style={{fontSize:15,width:20,textAlign:"center"}}>{item.icon}</span>{item.label}{item.id==="alerts"&&alertBadge>0&&<span style={{marginLeft:"auto",background:"#dc2626",color:"#fff",fontSize:10,fontWeight:700,padding:"2px 7px",borderRadius:10}}>{alertBadge}</span>}</button>;})}</nav>
        <div style={{padding:"12px 16px",borderTop:"1px solid rgba(255,255,255,0.06)"}}><div style={{fontSize:9,color:"rgba(255,255,255,0.25)",marginBottom:6,textTransform:"uppercase",letterSpacing:1}}>Allocation Mode</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6}}>{[{l:"Green",v:counts.green,c:"#047857"},{l:"Yellow",v:counts.yellow,c:"#b45309"},{l:"Red",v:counts.red,c:"#dc2626"},{l:"Critical",v:counts.critical,c:"#991b1b"}].map(function(s){return <div key={s.l} style={{textAlign:"center",padding:"6px 4px",borderRadius:8,background:"rgba(255,255,255,0.04)"}}><div style={{fontSize:18,fontWeight:700,color:s.c}}>{s.v}</div><div style={{fontSize:9,color:"rgba(255,255,255,0.35)",textTransform:"uppercase"}}>{s.l}</div></div>;})}</div></div>
        <div style={{padding:"14px 16px",borderTop:"1px solid rgba(255,255,255,0.06)",display:"flex",alignItems:"center",gap:10}}><div style={{width:32,height:32,borderRadius:"50%",background:"linear-gradient(135deg,#c4a35a,#8b7340)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,fontWeight:600,color:"#fff"}}>AP</div><div><div style={{fontSize:12,color:"rgba(255,255,255,0.75)",fontWeight:500}}>Aditya P.</div><div style={{fontSize:10,color:"rgba(255,255,255,0.3)"}}>Production Manager</div></div></div>
      </div>

      <div style={{marginLeft:220,flex:1}}>

        {/* CAPACITY */}
        {view==="capacity"&&!sel&&(<div>
          <div style={{padding:"24px 32px 18px",borderBottom:"1px solid #e5e5e5",background:"#fff"}}><h1 style={{margin:0,fontSize:22,fontWeight:700}}>Allocated Production Capacity</h1><p style={{margin:"6px 0 0",fontSize:14,color:"#777"}}>Shared ingredients split by depletion-weighted demand. Numbers show what each recipe can realistically produce.</p></div>
          <div style={{padding:"20px 32px"}}>
            <div style={{display:"flex",gap:8,marginBottom:18,flexWrap:"wrap",alignItems:"center"}}>
              {[{id:"all",l:"All ("+engine.recipes.length+")"},{id:"critical",l:"Critical ("+counts.critical+")",c:"#991b1b"},{id:"red",l:"Red ("+counts.red+")",c:"#dc2626"},{id:"yellow",l:"Yellow ("+counts.yellow+")",c:"#b45309"},{id:"green",l:"Green ("+counts.green+")",c:"#047857"}].map(function(f){return <button key={f.id} onClick={function(){setFilterTier(f.id);}} style={{padding:"7px 16px",borderRadius:8,border:filterTier===f.id?"2px solid "+(f.c||"#c4a35a"):"1px solid #ddd",background:filterTier===f.id?(f.c||"#c4a35a")+"12":"#fff",fontSize:13,fontWeight:filterTier===f.id?600:400,cursor:"pointer",fontFamily:"inherit",color:f.c||"#555"}}>{f.l}</button>;})}
              <div style={{marginLeft:"auto"}}><input placeholder="Search recipes..." value={searchR} onChange={function(e){setSearchR(e.target.value);}} style={{padding:"8px 16px",borderRadius:8,border:"1px solid #ddd",fontSize:14,width:240}} /></div>
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:8}}>
              {sorted.map(function(r){var bM=Math.max.apply(null,engine.recipes.map(function(x){return x.mx;}))||1;var pct=Math.min(100,Math.round((r.mx/bM)*100));
                return <div key={r.name} onClick={function(){setSel(r);}} style={{background:"#fff",borderRadius:12,border:"1px solid #e5e5e5",padding:"16px 20px",cursor:"pointer",borderLeft:"5px solid "+r.st.color}}>
                  <div style={{display:"flex",alignItems:"center",gap:16}}>
                    <div style={{minWidth:60,textAlign:"center"}}><div style={{fontSize:30,fontWeight:700,color:r.st.color,lineHeight:1}}>{r.mx}</div><div style={{fontSize:11,color:"#999",marginTop:2}}>batch{r.mx!==1?"es":""}</div></div>
                    <div style={{flex:1}}>
                      <div style={{fontSize:15,fontWeight:600}}>{r.name} <span style={{fontSize:12,color:"#aaa",fontWeight:400}}>{r.cat}</span></div>
                      <div style={{marginTop:6,height:6,borderRadius:3,background:"#eee",overflow:"hidden"}}><div style={{height:"100%",borderRadius:3,background:r.st.color,width:pct+"%"}} /></div>
                      <div style={{marginTop:5,fontSize:13,color:"#777"}}>{r.st.tier==="critical"?<span style={{color:"#991b1b",fontWeight:600}}>{r.mc} ingredients missing</span>:r.st.tier==="red"?<span style={{color:"#dc2626"}}>{r.mc} missing</span>:r.bn?<span>Bottleneck: <strong style={{color:"#ea580c"}}>{r.bn.split(" ").slice(0,3).join(" ")}</strong></span>:"All stocked"}</div>
                    </div>
                    <span style={{padding:"5px 12px",borderRadius:8,fontSize:11,fontWeight:700,background:r.st.bg,color:r.st.color}}>{r.st.label}</span>
                    <span style={{color:"#ccc",fontSize:18}}>{"\u203A"}</span>
                  </div>
                </div>;
              })}
            </div>
          </div>
        </div>)}

        {/* RECIPE DETAIL */}
        {sel&&(<div>
          <div style={{padding:"24px 32px 18px",borderBottom:"1px solid #e5e5e5",background:"#fff",borderLeft:"5px solid "+sel.st.color}}>
            <button onClick={function(){setSel(null);}} style={{fontSize:13,color:"#888",border:"none",background:"none",cursor:"pointer",marginBottom:8,fontFamily:"inherit",padding:0}}>{"\u2190"} Back</button>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
              <div><h1 style={{margin:0,fontSize:22,fontWeight:700}}>{sel.name}</h1><p style={{margin:"5px 0 0",fontSize:14,color:"#777"}}>{sel.cat} {"\u00B7"} {sel.ic} ingredients {"\u00B7"} {"$"+sel.cpb.toFixed(0)}/batch</p></div>
              <div style={{textAlign:"right"}}><div style={{fontSize:11,color:"#888",textTransform:"uppercase",fontWeight:600}}>Allocated Capacity</div><div style={{fontSize:48,fontWeight:700,color:sel.st.color,lineHeight:1.1}}>{sel.mx}</div><div style={{marginTop:4}}><span style={{padding:"4px 12px",borderRadius:8,fontSize:11,fontWeight:700,background:sel.st.bg,color:sel.st.color}}>{sel.st.label}</span></div></div>
            </div>
          </div>
          <div style={{padding:"20px 32px"}}>
            <div style={{background:"#fff",borderRadius:12,border:"1px solid #e5e5e5",overflow:"hidden"}}>
              <div style={{padding:"14px 18px",borderBottom:"1px solid #eee",fontSize:13,fontWeight:700,display:"flex",justifyContent:"space-between"}}><span>Ingredient Allocation</span><span style={{fontWeight:400,color:"#888"}}>Share % = this recipe's allocation of shared ingredients</span></div>
              <table style={{width:"100%",borderCollapse:"collapse"}}>
                <thead><tr style={{borderBottom:"2px solid #eee",background:"#fafaf8"}}>{["Ingredient","Per Batch","Packs","Total","Share","Allocated Batches","","Status"].map(function(h){return <th key={h} style={{padding:"12px 14px",fontSize:11,fontWeight:700,color:"#888",textTransform:"uppercase",textAlign:"left"}}>{h}</th>;})}</tr></thead>
                <tbody>{sel.ings.slice().sort(function(a,b){return a.cm-b.cm;}).map(function(ing,idx){
                  var isBN=ing.name===sel.bn;var bPct=sel.mx>0?Math.min(100,Math.round((sel.mx/Math.max(ing.cm,1))*100)):0;var bCol=ing.miss?"#991b1b":ing.cm===0?"#dc2626":isBN?"#ea580c":ing.cm<=sel.mx+1?"#eab308":"#047857";
                  return <tr key={idx} style={{borderBottom:"1px solid #f0f0f0",background:ing.miss?"#fef2f2":isBN?"#fff7ed":"transparent"}}>
                    <td style={{padding:"12px 14px",fontSize:13,fontWeight:isBN?700:500}}>{ing.name}</td>
                    <td style={{padding:"12px 14px",fontSize:13,color:"#666"}}>{ing.perBatch} {ing.unit}</td>
                    <td style={{padding:"12px 14px"}}><div style={{display:"flex",alignItems:"center",gap:6}}><input type="number" min="0" step="0.1" value={inv[ing.name]||0} onChange={function(e){us(ing.name,parseFloat(e.target.value)||0);}} style={{width:72,padding:"5px 8px",borderRadius:6,border:"1px solid #ddd",fontSize:13,fontWeight:600,textAlign:"center",fontFamily:"inherit"}} /><span style={{fontSize:10,color:"#bbb"}}>{"\u00D7"}{ing.ps}{ing.pu}</span></div></td>
                    <td style={{padding:"12px 14px",fontSize:13,fontWeight:600,color:ing.ts>0?"#047857":"#dc2626"}}>{ing.ts>0?ing.ts.toLocaleString()+" "+ing.pu:"0"}</td>
                    <td style={{padding:"12px 14px"}}>{ing.sh?<span style={{padding:"3px 10px",borderRadius:6,fontSize:12,fontWeight:600,background:"#f5f0ff",color:"#7c3aed"}}>{ing.share}%</span>:<span style={{fontSize:12,color:"#aaa"}}>100%</span>}</td>
                    <td style={{padding:"12px 14px",fontSize:18,fontWeight:700,color:bCol}}>{ing.cm>=99999?"\u221E":ing.cm.toLocaleString()}</td>
                    <td style={{padding:"12px 14px",width:80}}><div style={{width:"100%",height:8,borderRadius:4,background:"#eee",overflow:"hidden"}}><div style={{height:"100%",borderRadius:4,background:bCol,width:(ing.miss?100:bPct)+"%"}} /></div></td>
                    <td style={{padding:"12px 14px"}}>{ing.miss?<span style={{padding:"4px 10px",borderRadius:6,fontSize:11,fontWeight:700,background:"#fef2f2",color:"#dc2626"}}>MISSING</span>:isBN?<span style={{padding:"4px 10px",borderRadius:6,fontSize:11,fontWeight:700,background:"#fff7ed",color:"#ea580c"}}>BOTTLENECK</span>:<span style={{padding:"4px 10px",borderRadius:6,fontSize:11,fontWeight:600,background:"#ecfdf5",color:"#047857"}}>OK</span>}</td>
                  </tr>;
                })}</tbody>
              </table>
            </div>
          </div>
        </div>)}

        {/* ALERTS */}
        {view==="alerts"&&!sel&&(<div>
          <div style={{padding:"24px 32px 18px",borderBottom:"1px solid #e5e5e5",background:"#fff"}}><h1 style={{margin:0,fontSize:22,fontWeight:700}}>Daily Alerts</h1><p style={{margin:"6px 0 0",fontSize:14,color:"#777"}}>{alerts.length} alert{alerts.length!==1?"s":""}</p></div>
          <div style={{padding:"20px 32px"}}>
            {alerts.length===0?<div style={{textAlign:"center",padding:"60px"}}><div style={{fontSize:40}}>{"\u2705"}</div><div style={{fontSize:18,fontWeight:600,color:"#047857",marginTop:8}}>All Clear</div></div>
              :<div style={{display:"flex",flexDirection:"column",gap:10}}>{alerts.map(function(a,i){
                var cfg={critical:{border:"#991b1b",badge:"CRITICAL",badgeBg:"#991b1b",badgeText:"#fff"},red:{border:"#dc2626",badge:"CANNOT PRODUCE",badgeBg:"#fef2f2",badgeText:"#dc2626"},low_stock:{border:"#ea580c",badge:a.days!==undefined?a.days+"d LEFT":"LOW",badgeBg:"#fff7ed",badgeText:"#ea580c"},yellow:{border:"#b45309",badge:"RUNNING LOW",badgeBg:"#fffbeb",badgeText:"#b45309"}}[a.type]||{border:"#ddd",badge:"INFO",badgeBg:"#f5f5f5",badgeText:"#666"};
                return <div key={i} style={{background:"#fff",borderRadius:12,border:"1px solid #e5e5e5",borderLeft:"5px solid "+cfg.border,padding:"16px 20px",display:"flex",alignItems:"center",gap:16}}>
                  <div style={{flex:1}}><div style={{fontSize:15,fontWeight:700}}>{a.title}</div><div style={{fontSize:14,color:"#666",marginTop:4,lineHeight:1.5}}>{a.desc}</div></div>
                  <span style={{padding:"8px 16px",borderRadius:8,fontSize:13,fontWeight:700,background:cfg.badgeBg,color:cfg.badgeText,whiteSpace:"nowrap"}}>{cfg.badge}</span>
                </div>;
              })}</div>}
          </div>
        </div>)}

        {/* OVERRIDES */}
        {view==="overrides"&&!sel&&(<div>
          <div style={{padding:"24px 32px 18px",borderBottom:"1px solid #e5e5e5",background:"#fff"}}><h1 style={{margin:0,fontSize:22,fontWeight:700}}>Ingredient Overrides</h1><p style={{margin:"6px 0 0",fontSize:14,color:"#777"}}>Log when a chef reallocates ingredients</p></div>
          <div style={{padding:"20px 32px"}}>
            <div style={{background:"#fff",borderRadius:12,border:"1px solid #e5e5e5",padding:"20px 24px",marginBottom:20}}>
              <div style={{fontSize:15,fontWeight:700,marginBottom:12}}>New Override</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 100px 1fr 1fr 1fr auto",gap:10,alignItems:"end"}}>
                <div><div style={{fontSize:12,fontWeight:600,color:"#777",marginBottom:4}}>Ingredient</div><select value={ovIng} onChange={function(e){setOvIng(e.target.value);}} style={{width:"100%",padding:"8px 10px",borderRadius:8,border:"1px solid #ddd",fontSize:13,fontFamily:"inherit"}}><option value="">Select...</option>{Object.keys(RAW.ingredients).sort().map(function(n){return <option key={n} value={n}>{n}</option>;})}</select></div>
                <div><div style={{fontSize:12,fontWeight:600,color:"#777",marginBottom:4}}>Qty</div><input type="number" value={ovQty} onChange={function(e){setOvQty(e.target.value);}} style={{width:"100%",padding:"8px 10px",borderRadius:8,border:"1px solid #ddd",fontSize:13,fontFamily:"inherit"}} /></div>
                <div><div style={{fontSize:12,fontWeight:600,color:"#777",marginBottom:4}}>From</div><select value={ovFrom} onChange={function(e){setOvFrom(e.target.value);}} style={{width:"100%",padding:"8px 10px",borderRadius:8,border:"1px solid #ddd",fontSize:13,fontFamily:"inherit"}}><option value="">General stock</option>{RAW.recipes.map(function(r){return <option key={r.name} value={r.name}>{r.name}</option>;})}</select></div>
                <div><div style={{fontSize:12,fontWeight:600,color:"#777",marginBottom:4}}>Used For</div><select value={ovTo} onChange={function(e){setOvTo(e.target.value);}} style={{width:"100%",padding:"8px 10px",borderRadius:8,border:"1px solid #ddd",fontSize:13,fontFamily:"inherit"}}><option value="">Off-menu</option>{RAW.recipes.map(function(r){return <option key={r.name} value={r.name}>{r.name}</option>;})}</select></div>
                <div><div style={{fontSize:12,fontWeight:600,color:"#777",marginBottom:4}}>Reason</div><input value={ovReason} onChange={function(e){setOvReason(e.target.value);}} placeholder="VIP request" style={{width:"100%",padding:"8px 10px",borderRadius:8,border:"1px solid #ddd",fontSize:13,fontFamily:"inherit"}} /></div>
                <button onClick={addOv} disabled={!ovIng||!ovQty} style={{padding:"8px 20px",borderRadius:8,border:"none",background:ovIng&&ovQty?"#1a1a2e":"#e5e5e5",color:ovIng&&ovQty?"#fff":"#999",fontSize:13,fontWeight:600,cursor:ovIng&&ovQty?"pointer":"not-allowed",fontFamily:"inherit",height:40}}>Log</button>
              </div>
            </div>
            {overrides.length===0?<div style={{textAlign:"center",padding:"40px",color:"#aaa",fontSize:14}}>No overrides logged</div>
              :<div style={{background:"#fff",borderRadius:12,border:"1px solid #e5e5e5",overflow:"hidden"}}><table style={{width:"100%",borderCollapse:"collapse"}}><thead><tr style={{borderBottom:"2px solid #eee"}}>{["Time","Ingredient","Qty","From","To","Reason","By"].map(function(h){return <th key={h} style={{padding:"12px 14px",fontSize:11,fontWeight:700,color:"#888",textTransform:"uppercase",textAlign:"left"}}>{h}</th>;})}</tr></thead><tbody>{overrides.map(function(o){return <tr key={o.id} style={{borderBottom:"1px solid #f0f0f0"}}><td style={{padding:"12px 14px",fontSize:13,color:"#888"}}>{o.time}</td><td style={{padding:"12px 14px",fontSize:13,fontWeight:600}}>{o.ing.split(" ").slice(0,3).join(" ")}</td><td style={{padding:"12px 14px",fontSize:14,fontWeight:700,color:"#dc2626"}}>{"-"+o.qty}</td><td style={{padding:"12px 14px",fontSize:13}}>{o.from||"General"}</td><td style={{padding:"12px 14px",fontSize:13}}>{o.to||"Off-menu"}</td><td style={{padding:"12px 14px",fontSize:13,color:"#888"}}>{o.reason||"\u2014"}</td><td style={{padding:"12px 14px",fontSize:13}}>{o.user}</td></tr>;})}</tbody></table></div>}
          </div>
        </div>)}

        {/* CALENDAR */}
        {view==="calendar"&&!sel&&(<div>
          <div style={{padding:"24px 32px 18px",borderBottom:"1px solid #e5e5e5",background:"#fff"}}><h1 style={{margin:0,fontSize:22,fontWeight:700}}>Weekly Production Plan</h1><p style={{margin:"6px 0 0",fontSize:14,color:"#777"}}>Estimated batches from Jan-Mar 2026 depletion data</p></div>
          <div style={{padding:"20px 32px"}}>
            <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:10}}>
              {DOW_ORDER.map(function(day,di){var today=new Date().getDay();var isToday=(today===0&&di===6)||(today===di+1);var dayR=calendar[day]||[];
                return <div key={day} style={{background:"#fff",borderRadius:12,border:"1px solid #e5e5e5",padding:"14px",borderTop:isToday?"4px solid #c4a35a":"4px solid transparent",minHeight:280}}>
                  <div style={{fontSize:14,fontWeight:700,color:isToday?"#c4a35a":"#1a1a2e",marginBottom:10}}>{DOW_SHORT[di]}{isToday&&<span style={{fontSize:10,background:"#c4a35a",color:"#fff",padding:"2px 6px",borderRadius:4,marginLeft:6}}>TODAY</span>}</div>
                  <div style={{fontSize:12,color:"#aaa",marginBottom:8}}>{dayR.length} recipe{dayR.length!==1?"s":""}</div>
                  {dayR.length===0?<div style={{fontSize:13,color:"#ccc",padding:"10px 0"}}>No data</div>
                    :dayR.slice(0,12).map(function(r){return <div key={r.name} style={{padding:"6px 8px",borderRadius:6,marginBottom:4,background:r.ok?"#ecfdf5":"#fef2f2"}}>
                      <div style={{fontSize:12,fontWeight:600,color:r.ok?"#047857":"#dc2626"}}>{r.name.length>20?r.name.substring(0,20)+"..":r.name}</div>
                      <div style={{fontSize:11,color:"#888",marginTop:1}}>{r.est}x est{!r.ok?" \u2022 max "+r.mx:""}</div>
                    </div>;})}
                </div>;
              })}
            </div>
          </div>
        </div>)}

        {/* INVENTORY */}
        {view==="inventory"&&!sel&&(<div>
          <div style={{padding:"24px 32px 18px",borderBottom:"1px solid #e5e5e5",background:"#fff"}}><h1 style={{margin:0,fontSize:22,fontWeight:700}}>Inventory</h1><p style={{margin:"6px 0 0",fontSize:14,color:"#777"}}>{Object.keys(RAW.ingredients).length} ingredients. Edit packs to recalculate all allocations.</p></div>
          <div style={{padding:"20px 32px"}}>
            <div style={{display:"flex",justifyContent:"flex-end",marginBottom:14}}><input placeholder="Search ingredients..." value={searchI} onChange={function(e){setSearchI(e.target.value);}} style={{padding:"8px 16px",borderRadius:8,border:"1px solid #ddd",fontSize:14,width:280}} /></div>
            <div style={{background:"#fff",borderRadius:12,border:"1px solid #e5e5e5",overflow:"hidden"}}>
              <table style={{width:"100%",borderCollapse:"collapse"}}>
                <thead><tr style={{borderBottom:"2px solid #eee"}}>{["Ingredient","Pack","Packs","Total","Avg/Day","Days Left","Recipes"].map(function(h){return <th key={h} style={{padding:"12px 14px",fontSize:11,fontWeight:700,color:"#888",textTransform:"uppercase",textAlign:"left"}}>{h}</th>;})}</tr></thead>
                <tbody>{Object.entries(RAW.ingredients).filter(function(e){return !searchI||e[0].toLowerCase().indexOf(searchI.toLowerCase())>=0;}).sort(function(a,b){var aA=a[1].avg_daily||0,bA=b[1].avg_daily||0;var pa=pp(a[0]),pb=pp(b[0]);var aT=(inv[a[0]]||0)*(pa?pa.s:1),bT=(inv[b[0]]||0)*(pb?pb.s:1);var aD=aA>0?aT/aA:9999,bD=bA>0?bT/bA:9999;return aD-bD;}).map(function(e){
                  var n=e[0],info=e[1],sc=inv[n]||0;var pk=pp(n);var ps=pk?pk.s:1,pu=pk?pk.u:info.unit;var total=sc*ps;var avg=info.avg_daily||0;var dL=avg>0?Math.round(total/avg):null;var urg=dL!==null?(dL<=2?"#dc2626":dL<=5?"#ea580c":dL<=10?"#b45309":"#047857"):"#ccc";
                  return <tr key={n} style={{borderBottom:"1px solid #f0f0f0"}}><td style={{padding:"12px 14px",fontSize:13,fontWeight:500,maxWidth:240,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{n}</td><td style={{padding:"12px 14px",fontSize:12,color:"#888"}}>{ps} {pu}</td><td style={{padding:"12px 14px"}}><input type="number" min="0" step="0.1" value={sc} onChange={function(ev){us(n,parseFloat(ev.target.value)||0);}} style={{width:80,padding:"5px 8px",borderRadius:6,border:"1px solid #ddd",fontSize:13,fontWeight:600,textAlign:"center",fontFamily:"inherit"}} /></td><td style={{padding:"12px 14px",fontSize:13,fontWeight:600,color:total>0?"#047857":"#dc2626"}}>{total>0?Math.round(total)+" "+pu:"0"}</td><td style={{padding:"12px 14px",fontSize:13}}>{avg>0?<span style={{color:"#047857",fontWeight:600}}>{avg.toFixed(1)}</span>:<span style={{color:"#ccc"}}>{"\u2014"}</span>}</td><td style={{padding:"12px 14px"}}>{dL!==null?<span style={{padding:"4px 12px",borderRadius:8,fontSize:13,fontWeight:700,background:urg+"15",color:urg}}>{dL} days</span>:<span style={{color:"#ccc"}}>{"\u2014"}</span>}</td><td style={{padding:"12px 14px"}}><span style={{padding:"3px 10px",borderRadius:6,fontSize:12,fontWeight:600,background:(info.recipe_count||1)>1?"#f5f0ff":"#f5f5f5",color:(info.recipe_count||1)>1?"#7c3aed":"#999"}}>{info.recipe_count||1}</span></td></tr>;
                })}</tbody>
              </table>
            </div>
          </div>
        </div>)}

        {/* ALL RECIPES */}
        {view==="recipes"&&!sel&&(<div>
          <div style={{padding:"24px 32px 18px",borderBottom:"1px solid #e5e5e5",background:"#fff"}}><h1 style={{margin:0,fontSize:22,fontWeight:700}}>All Recipes</h1><p style={{margin:"6px 0 0",fontSize:14,color:"#777"}}>{RAW.recipes.length} recipes</p></div>
          <div style={{padding:"20px 32px"}}>
            <div style={{marginBottom:16}}><input placeholder="Search recipes..." value={searchAll} onChange={function(e){setSearchAll(e.target.value);}} style={{padding:"10px 18px",borderRadius:10,border:"1px solid #ddd",fontSize:15,width:"100%",maxWidth:400}} /></div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:12}}>
              {engine.recipes.filter(function(r){return !searchAll||r.name.toLowerCase().indexOf(searchAll.toLowerCase())>=0;}).sort(function(a,b){var o={critical:0,red:1,yellow:2,green:3};return(o[a.st.tier]||3)-(o[b.st.tier]||3);}).map(function(r){return <div key={r.name} onClick={function(){setSel(r);}} style={{background:"#fff",borderRadius:12,border:"1px solid #e5e5e5",padding:"16px 20px",cursor:"pointer",borderLeft:"4px solid "+r.st.color}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}><div><div style={{fontSize:15,fontWeight:600}}>{r.name}</div><div style={{fontSize:12,color:"#888",marginTop:3}}>{r.ic} ings {"\u00B7"} {r.mc>0?<span style={{color:"#dc2626"}}>{r.mc} missing</span>:"all stocked"}</div></div><div style={{fontSize:28,fontWeight:700,color:r.st.color,lineHeight:1}}>{r.mx}</div></div>
                <div style={{marginTop:8}}><span style={{padding:"4px 10px",borderRadius:6,fontSize:11,fontWeight:600,background:r.st.bg,color:r.st.color}}>{r.st.label}</span></div>
              </div>;})}
            </div>
          </div>
        </div>)}

      </div>
      <style>{`input:focus{outline:none;border-color:#c4a35a!important;box-shadow:0 0 0 3px rgba(196,163,90,0.15)!important}::-webkit-scrollbar{width:6px}::-webkit-scrollbar-thumb{background:#ddd;border-radius:3px}tr:hover{background:#fafaf8!important}`}</style>
    </div>
  );
}
